const suppliers = [
  { name: "ABC Electronics", email: "user@example.com", category: "Electronics" },
  { name: "XYZ Hardware", email: "user@example.com", category: "Hardware" },
  { name: "Tech Solutions", email: "user@example.com", category: "Software" }
];

return suppliers.map(s => ({ json: s }));

// Gmail already parsed the data for us!
const fromEmail = $json.from?.value?.[0]?.address || 'user@example.com';
const toEmail = $json.to?.value?.[0]?.address || '';
const subject = $json.subject || 'No Subject';

// Check if this is a reply to our supplier email (the +supplier emails)
const supplierEmail = toEmail.includes('+supplier') ? toEmail : fromEmail;

// Attachments are in binary data (we'll handle in next node)
// For now, just check if email likely has attachments
const hasAttachments = $json.text?.includes('attached') || $json.html?.includes('attached');

return [{
  json: {
    messageId: $json.id,
    supplierEmail: supplierEmail,
    fromEmail: fromEmail,
    subject: subject,
    receivedDate: new Date().toISOString().split('T')[0],
    emailText: $json.text,
    hasAttachments: hasAttachments
  }
}];

// Collect extracted text from all PDF items
const items = $input.all();

const extractedText = items
  .map(item => item.json.text || item.json.data || '')
  .filter(t => t.trim() !== '')
  .join('\n\n---\n\n');

// Get supplier info safely
const quotesData = $('Get quotes to process').all();
const supplierData = quotesData.length > 0 ? quotesData[0].json : {};

if (!extractedText) {
  return [{
    json: {
      error: 'No extracted text found',
      debug_sample: items[0]?.json || {}
    }
  }];
}

return [{
  json: {
    supplier_name: supplierData.supplier_name || 'Unknown Supplier',
    supplier_email: supplierData.supplier_email || 'user@example.com',
    category: supplierData.category || 'Unknown',
    document_text: extractedText
  }
}];

// Get the products string from Information Extractor
const productsString = $input.first().json.output['Products List'] || '[]';

// Parse the JSON string
let products = [];
try {
  products = JSON.parse(productsString);
} catch (error) {
  return [{
    json: {
      error: 'Failed to parse products',
      raw_string: productsString
    }
  }];
}

// Get supplier info
const supplierData = $('Prepare for openAI').first().json;



// Create one row per product
return products.map(product => ({
  json: {
    supplier_name: supplierData.supplier_name,
    supplier_email: supplierData.supplier_email,
    category: supplierData.category,
    product_name: product.product_name,
    price: parseFloat(product.price) || 0,
    currency: product.currency || 'NGN',
    quantity: product.quantity || '1',
    notes: product.notes || '',
    source_file: supplierData.file_name || 'unknown',
    supplier_phone: $input.first().json.output['supplier_phone'] || '',
    extracted_date: new Date().toISOString().split('T')[0],

  }
}));

// Process ALL suppliers that need follow-up
const suppliers = $input.all().map(item => item.json);

return suppliers.map(supplier => {
  const requestDate = new Date(supplier.request_date || supplier.request_sent_date);
  const daysSince = Math.floor((new Date() - requestDate) / (1000 * 60 * 60 * 24));

  // Create personalized message
  let message = `Hi ${supplier.supplier_name},\n\n`;

  if (daysSince === 3) {
    message += `This is a friendly reminder about the price quote we requested ${daysSince} days ago for ${supplier.category}.\n\n`;
    message += `Could you please send us your pricing when you get a chance?\n\n`;
  } else if (daysSince === 5) {
    message += `Following up on our price quote request from ${daysSince} days ago.\n\n`;
    message += `We'd appreciate receiving your quote soon as we're comparing options.\n\n`;
  } else if (daysSince >= 7) {
    message += `Final reminder: We requested a quote ${daysSince} days ago for ${supplier.category}.\n\n`;
    message += `Please let us know if you're able to provide pricing.\n\n`;
  }

  message += `Category: ${supplier.category}\n`;
  message += `Original Request: ${requestDate.toLocaleDateString()}\n\n`;
  message += `Thank you!\nProcurement Team`;

  // Format phone number
  let phoneNumber = supplier.phone_number || '';
  if (phoneNumber && !phoneNumber.startsWith('+')) {
    phoneNumber = '+' + phoneNumber;
  }

  return {
    json: {
      supplier_name: supplier.supplier_name,
      supplier_email: supplier.supplier_email,
      phone_number: phoneNumber,
      message: message,
      days_since_request: daysSince,
      follow_up_type: daysSince === 3 ? 'First Reminder' : daysSince === 5 ? 'Second Reminder' : 'Final Reminder',
      follow_up_count: supplier.follow_up_count || 0
    }
  };
});

// Check which quotes need follow-up
const today = new Date();
const quotes = $input.all().map(item => item.json);

const needFollowUp = quotes.filter(quote => {
  // Skip if already received
  if (quote.quote_received === 'Yes') {
    return false;
  }

  // Calculate days since request
  const requestDate = new Date(quote.request_date || quote.request_sent_date);
  const daysSince = Math.floor((today - requestDate) / (1000 * 60 * 60 * 24));

  // Follow up after 3 days, then 5 days, then 7 days
  const shouldFollowUp = daysSince === 3 || daysSince === 5 || daysSince === 7;

  return shouldFollowUp;
});

return needFollowUp.map(quote => ({ json: quote }));
